using System;
using System.Net.Http;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

namespace WebhookProxy
{
    public class Startup
    {
        public void ConfigureServices(IServiceCollection services)
        {
            services.AddTransient<IWebhookHandler, WebhookHandler>();
        }

        public void Configure(IApplicationBuilder app, ILoggerFactory loggerFactory)
        {
            app.UseRouting();
            app.UseEndpoints(endpoints =>
            {
                endpoints.Map("/", async context =>
                {
                    var userUrl = context.Request.Query["url"];
                    if (string.IsNullOrEmpty(userUrl))
                    {
                        context.Response.StatusCode = 400;
                        return;
                    }

                    var httpClient = new HttpClient();
                    var response = await httpClient.GetAsync(userUrl);

                    if (response.IsSuccessStatusCode)
                    {
                        context.Response.StatusCode = 200;
                        context.Response.ContentType = "application/json";
                        await response.Content.CopyToAsync(context.Response.Body);
                    }
                    else
                    {
                        context.Response.StatusCode = 500;
                        loggerFactory.CreateLogger<Startup>().LogError($"Failed to fetch content from URL: {userUrl}");
                    }
                });
            });
        }
    }

    public interface IWebhookHandler
    {
        Task HandleAsync(string userUrl);
    }

    public class WebhookHandler : IWebhookHandler
    {
        private readonly HttpClient _httpClient;

        public WebhookHandler(HttpClient httpClient)
        {
            _httpClient = httpClient;
        }

        public async Task HandleAsync(string userUrl)
        {
            var response = await _httpClient.GetAsync(userUrl);

            if (response.IsSuccessStatusCode)
            {
                Console.WriteLine($"Received content from URL: {userUrl}");
                Console.WriteLine(await response.Content.ReadAsStringAsync());
            }
            else
            {
